-- Create the prior_season_matches table if it doesn't exist
CREATE TABLE IF NOT EXISTS prior_season_matches (
  id            SERIAL PRIMARY KEY,
  season        TEXT    NOT NULL DEFAULT '24/25',
  league_name   TEXT    NOT NULL,
  league_level  TEXT    NOT NULL CHECK (league_level IN ('kreisklasse', 'kreisliga', 'bezirksliga')),
  league_number TEXT,
  home_team     TEXT    NOT NULL,
  away_team     TEXT    NOT NULL,
  home_score    INTEGER NOT NULL,
  away_score    INTEGER NOT NULL,
  match_date    DATE    NOT NULL,
  CONSTRAINT unique_match UNIQUE (league_number, home_team, away_team, match_date)
);
CREATE INDEX IF NOT EXISTS idx_psm_home ON prior_season_matches (home_team);
CREATE INDEX IF NOT EXISTS idx_psm_away ON prior_season_matches (away_team);
CREATE INDEX IF NOT EXISTS idx_psm_league ON prior_season_matches (league_level, league_number);

-- ============================================================
-- Bezirksliga Oberbayern Süd (season 25/26)
-- league_level='bezirksliga', league_number='310073'
-- ============================================================
ON CONFLICT ON CONSTRAINT unique_match DO NOTHING;

